class Solution:
    def mergeSimilarItems(self, items1, items2):
        vals = set()
        for v, w in items1:
            vals.add(v)
        for v, w in items2:
            vals.add(v)
        res = []
        for v in sorted(vals):
            total = 0
            for vv, w in items1:
                if vv == v:
                    total += w
            for vv, w in items2:
                if vv == v:
                    total += w
            res.append([v, total])
        return res

