class Solution:
    def mergeSimilarItems(self, items1, items2):
        from collections import defaultdict
        acc = defaultdict(int)
        for v, w in items1:
            acc[v] += w
        for v, w in items2:
            acc[v] += w
        return [[v, acc[v]] for v in sorted(acc)]

