var mergeSimilarItems = function(items1, items2) {
    const acc = new Map();
    for (const [v, w] of items1) acc.set(v, (acc.get(v) || 0) + w);
    for (const [v, w] of items2) acc.set(v, (acc.get(v) || 0) + w);
    return [...acc.keys()].sort((a, b) => a - b).map(v => [v, acc.get(v)]);
};
